      &:first-of-type button {
        border-top-left-radius: 10px;
        border-bottom-left-radius: 10px;
      }

      &:last-of-type button {
        border-top-right-radius: 10px;
        border-bottom-right-radius: 10px;
      }
    }
  }

  > ul {
    justify-content: flex-start;
    align-items: center;
    list-style: none;
    padding: 0;

    button {
      border: none;
      padding: 5px;
      cursor: pointer;
      background-color: #33353a;

      &:hover, &.active {
